function enhanceNavigation(){document.querySelectorAll('.links').forEach(nav=>{const link=[...nav.children].find(el=>el.matches&&el.matches('a[data-i18n="solutions"]'));if(!link||link.closest('.nav-dropdown'))return;const wrap=document.createElement('div');wrap.className='nav-dropdown';link.parentNode.insertBefore(wrap,link);wrap.appendChild(link);const menu=document.createElement('div');menu.className='solution-menu';menu.innerHTML='<a href="ai-healthcare.html"><b data-i18n="health">AI Healthcare</b><small data-i18n="menuHealthDesc">Imaging, devices, planning and agents</small></a><a href="ai-agent.html"><b data-i18n="agentApplianceShort">Medical AI Agent</b><small data-i18n="menuAgentDesc">Hospital workflow AI appliance</small></a><a href="ai-agriculture.html"><b data-i18n="agri">AI Agriculture</b><small data-i18n="menuAgriDesc">Autonomous inspection and crop intelligence</small></a>';wrap.appendChild(menu)})}
document.addEventListener('DOMContentLoaded',enhanceNavigation);
function init(){let lang=localStorage.getItem('scovion-lang')||'en';if(!copy[lang])lang='en';document.documentElement.lang=lang;document.querySelectorAll('[data-i18n]').forEach(e=>e.textContent=copy[lang][e.dataset.i18n]||copy.en[e.dataset.i18n]||e.textContent);const sel=document.querySelector('#language');if(sel){sel.innerHTML=languages.map(([value,label])=>`<option value="${value}">${label}</option>`).join('');sel.value=lang;sel.onchange=()=>{localStorage.setItem('scovion-lang',sel.value);init()}}const menu=document.querySelector('.menu');if(menu)menu.onclick=()=>document.querySelector('.links').classList.toggle('open');document.querySelectorAll('[data-year]').forEach(e=>e.textContent=new Date().getFullYear())}document.addEventListener('DOMContentLoaded',init);
